  );
  sichtbareSpalten: string[] = ['inv_nr', 'typ', 'art', 'actions'];
  sichtbareSpaltenPruefungen: string[] = [
    'datum',
    'taetigkeit',
    'name_pruefer',
    'actions',
  ];

  formModul = new FormGroup({
    id: new FormControl(''),
    inv_nr: new FormControl('', Validators.required),
