              fw_plz: details.fw_plz,
              fw_ort: details.fw_ort,
              fw_email: details.fw_email,
              fw_telefon: details.fw_telefon,
              fw_kdt: details.fw_kdt,
              fw_webseite: details.fw_webseite,
              fw_konto: details.fw_konto,
              fw_iban: details.fw_iban,
              fw_bic: details.fw_bic
            })
            this.globalDataService.erstelleMessage("success","Konfiguration erfolgreich gespeichert!");
          } catch (e: any) {
            this.globalDataService.erstelleMessage("error", e);
          }
        },
        error: (error: any) => {
          this.globalDataService.errorAnzeigen(error);
        }
      });
    } else {
      this.globalDataService.patch(this.modul2, idValue, object, false).subscribe({
        next: (erg: any) => {
          try {
            const details: IKonfiguration = erg;
            this.formKonfig.setValue({
              id: details.id,
              fw_nummer: details.fw_nummer,
              fw_name: details.fw_name,
              fw_street: details.fw_street,
              fw_plz: details.fw_plz,
              fw_ort: details.fw_ort,
              fw_email: details.fw_email,
              fw_telefon: details.fw_telefon,
              fw_kdt: details.fw_kdt,
              fw_webseite: details.fw_webseite,
              fw_konto: details.fw_konto,
              fw_iban: details.fw_iban,
              fw_bic: details.fw_bic
            })
            this.globalDataService.erstelleMessage("success","Konfiguration erfolgreich geändert!");
          } catch (e: any) {
            this.globalDataService.erstelleMessage("error", e);
          }
        },
        error: (error: any) => {
          this.globalDataService.errorAnzeigen(error);
        }
      });
    }
  }

  backupImport(backup_name: any): void {
    const object = {
      "backup": backup_name.name
    }

    this.globalDataService.post("backup/restore", object, false).subscribe({
      next: (erg: any) => {
        try {
          this.backup_msg = erg.msg;
          this.globalDataService.erstelleMessage("success",this.backup_msg);
          sessionStorage.clear();
          document.cookie.split('; ').forEach(cookie => {
            const [name] = cookie.split('=');
            document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
          });
          this.router.navigate(['/login']);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  backupErstellen(): void {
    this.globalDataService.post("backup", {}, false).subscribe({
      next: (erg: any) => {
        try {
          this.backup_msg = erg.msg;
          this.backups = this.convertBackups(erg.backups);
          this.globalDataService.erstelleMessage("success",this.backup_msg);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  backupDownload(backup_name: any): void {
    const object = {
      "backup": backup_name.name
    }

    this.globalDataService.postBlob("backup/file", object).subscribe({
      next: (blob: Blob) => {
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = backup_name.name;
        document.body.appendChild(a);
        a.click();
        a.remove();
        URL.revokeObjectURL(url);
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  backupLoeschen(backup_name: any): void {
    const object = {
      "backup": backup_name.name
    }

    this.globalDataService.post("backup/delete", object, false).subscribe({
      next: (erg: any) => {
        try {
          this.backup_msg = erg.msg;
          this.backups = this.convertBackups(erg.backups);
          this.globalDataService.erstelleMessage("success",this.backup_msg);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  mediaCleanup(deleteFiles: boolean): void {
    if (this.cleanupRunning) {
      return;
    }

    this.cleanupRunning = true;
    const payload = {
      target: this.cleanupTarget,
      delete: deleteFiles,
    };

    this.globalDataService.cleanupOrphanMedia(payload).subscribe({
      next: (erg: any) => {
        const summary = erg?.summary ?? {};
        const orphanCount = summary.orphan ?? 0;
        const deletedCount = erg?.deleted ?? 0;
        this.cleanupSummary = `Ergebnis: ${orphanCount} verwaist gefunden, ${deletedCount} gelöscht.`;
        this.cleanupFiles = [];

        for (const item of (erg?.items ?? [])) {
          const target = String(item?.target ?? '');
          for (const orphan of (item?.orphans ?? [])) {
            this.cleanupFiles.push({
              target,
              targetLabel: this.getCleanupTargetLabel(target),
              filename: orphan,
            });
          }
        }

        const message = `Medien bereinigt: ${deletedCount} gelöscht, ${orphanCount} verwaist gefunden.`;
        this.globalDataService.erstelleMessage('success', message);
        this.cleanupRunning = false;
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
        this.cleanupRunning = false;
      }
    });
  }

  getCleanupTargetLabel(target: string): string {
    return this.cleanupTargetLabels[target] ?? target;
  }

  convertBackups(backup_array:any ): any {
    const version = environment.version;
    let data = [];
    for (let i = 0; i < backup_array.length; i++) {
      const file = backup_array[i];
      let backup_version = file.split('_');
      backup_version = backup_version[1];

      if (backup_version == version || backup_version == 'test') {
        const dict = {
          "name": file,
        }
        data.push(dict);
      }
    }
    data = this.globalDataService.arraySortByKeyDesc(data, "name");
    return data;
  }
}

import { Component, HostListener, OnInit, inject } from '@angular/core';
import { Router } from '@angular/router';
import { FormBuilder, FormGroup, Validators, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { GlobalDataService } from '../_service/global-data.service';
import { MatCardModule } from '@angular/material/card';
import { MatFormField, MatLabel, MatSuffix, MatError } from '@angular/material/form-field';
import { MatInput } from '@angular/material/input';
import { MatIcon } from '@angular/material/icon';
import { MatButton, MatIconButton } from '@angular/material/button';
import { environment } from 'src/environments/environment';
import { CommonModule } from '@angular/common';
import { finalize, switchMap } from 'rxjs';

type VersionInfo = {
  version: string;
  commit: string;
  channel: string;
  builtAt?: string;
};

@Component({
    selector: 'app-login',
    templateUrl: './login.component.html',
    styleUrls: ['./login.component.sass'],
    imports: [
      CommonModule,
      MatCardModule,
      FormsModule,
      ReactiveFormsModule,
      MatFormField,
      MatLabel,
      MatInput,
      MatError,
      MatIcon,
      MatSuffix,
      MatButton,
      MatIconButton
    ]
})

export class LoginComponent implements OnInit {
  private formBuilder = inject(FormBuilder);
  private router = inject(Router);
  private globalDataService = inject(GlobalDataService);

  title: string = environment.title;
  modul: string = "auth/login";
  form!: FormGroup;
  versionInfo?: VersionInfo;
  screenResolution = '';
  isSubmitting = false;

  public showPassword: boolean = false;

  public togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword;
  }

  ngOnInit(): void {
    this.globalDataService.getURL<VersionInfo>('/assets/version.json').subscribe({
      next: (v) => (this.versionInfo = v),
      error: () => (this.versionInfo = undefined),
    });

    this.updateScreenResolution();

    this.clearLoginSessionState();

    this.form = this.formBuilder.group({
      user: ['', Validators.required],
      pwd: ['', Validators.required]
    });
  }

  get isTestVersion(): boolean {
    const version = String(this.versionInfo?.version ?? '').toLowerCase();
    const channel = String(this.versionInfo?.channel ?? '').toLowerCase();
    return version.includes('test') || channel.includes('test');
  }

  @HostListener('window:resize')
  onWindowResize(): void {
    this.updateScreenResolution();
  }

  private updateScreenResolution(): void {
    if (typeof window === 'undefined') {
      this.screenResolution = '';
      return;
    }
    this.screenResolution = `${window.innerWidth} x ${window.innerHeight}px`;
  }

  private clearLoginSessionState(): void {
    if (typeof sessionStorage === 'undefined') {
      return;
    }

    const keysToClear = ['PageNumber', 'Benutzername', 'public_token_global', 'auth_guard_ok_until'];
    keysToClear.forEach((key) => sessionStorage.removeItem(key));

    for (let i = sessionStorage.length - 1; i >= 0; i--) {
      const key = sessionStorage.key(i);
      if (key && /^Page\d+$/.test(key)) {
        sessionStorage.removeItem(key);
      }
    }
  }

  get f() { return this.form.controls; }

  anmelden(): void {
    if (this.form.invalid || this.isSubmitting) {
      this.form.markAllAsTouched();
      return;
    }

    this.isSubmitting = true;

    const data = {
      "username": this.f.user.value,
      "password": this.f.pwd.value
    };

    this.globalDataService
      .get('auth/csrf')
      .pipe(switchMap(() => this.globalDataService.post(this.modul, data, false)))
      .pipe(finalize(() => (this.isSubmitting = false)))
      .subscribe({
        next: (erg: any) => {
          try {
            this.router.navigate(['/start']);
          } catch (e: any) {
            this.globalDataService.erstelleMessage("error", e);
          }
        },
        error: (error: any) => {
          this.globalDataService.errorAnzeigen(error);
        }
      });
  }
}

import { Component, OnInit, inject, ViewChild, ElementRef } from '@angular/core';

import { FormControl, FormGroup, Validators, FormsModule, ReactiveFormsModule, ValidatorFn, AbstractControl } from '@angular/forms';
import { IMitglied } from 'src/app/_interface/mitglied';
import { GlobalDataService } from 'src/app/_service/global-data.service';
import { HeaderComponent } from '../_template/header/header.component';
import { MatCardModule } from '@angular/material/card';
import { MatFormField, MatLabel, MatError } from '@angular/material/form-field';
import { MatButton } from '@angular/material/button';
import { MatInput } from '@angular/material/input';
import { MatCheckbox } from '@angular/material/checkbox';
import { MatOption, MatSelect } from '@angular/material/select';
import { Router } from '@angular/router';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatPaginator, MatPaginatorModule } from '@angular/material/paginator';
import { MatIconModule } from '@angular/material/icon';
import * as Papa from 'papaparse';
import { MatSort } from '@angular/material/sort';

type RenameMap = {
  [originalKey: string]: string;
};

type ImportChange = {
  action: 'CREATE' | 'UPDATE';
  row: number;
  stbnr: number;
  geburtsdatum: string;
  name: string;
  changed_fields: string[];
};

type ImportSummary = {
  created: number;
  updated: number;
  unchanged: number;
  total_changes: number;
  total_rows: number;
};

@Component({
    selector: 'app-mitglied',
    imports: [
    HeaderComponent,
    MatCardModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormField,
    MatLabel,
    MatButton,
    MatInput,
    MatError,
    MatCheckbox,
    MatSelect,
    MatOption,
    MatTableModule,
    MatPaginatorModule,
    MatSort,
    MatIconModule
],
    templateUrl: './mitglied.component.html',
    styleUrl: './mitglied.component.sass'
})

export class MitgliedComponent implements OnInit {
  globalDataService = inject(GlobalDataService);
  router = inject(Router);

  dataSource = new MatTableDataSource<IMitglied>([]);

  @ViewChild(MatPaginator) set matPaginator(p: MatPaginator | undefined) {
    if (p) this.dataSource.paginator = p;
  }

  @ViewChild(MatSort) set matSort(s: MatSort | undefined) {
    if (s) this.dataSource.sort = s;
  }

  @ViewChild('fileInput') fileInput!: ElementRef<HTMLInputElement>;

  title = "Mitglieder Verwaltung";
  modul = "mitglieder";

  mitglieder: IMitglied[] = [];
  breadcrumb: any = [];
  importRows: any[] = [];
  importChanges: ImportChange[] = [];
  importSummary: ImportSummary | null = null;

  formAuswahl = new FormGroup({
    mitglied: new FormControl(0)
  });

  formModul = new FormGroup({
    id: new FormControl(''),
    stbnr: new FormControl(0, Validators.required),
    vorname: new FormControl('', Validators.required),
    nachname: new FormControl('', Validators.required),
    dienstgrad: new FormControl(''),
    svnr: new FormControl('', [
      Validators.minLength(4),
      Validators.maxLength(4),
      Validators.pattern(/^\d{4}$/)
    ]),
    geburtsdatum: new FormControl('', [
      Validators.required,
      Validators.pattern(/^([0-3]\d)\.([0-1]\d)\.(\d{4})$/),
      this.validDateDDMMYYYY()
    ]),
    hauptberuflich: new FormControl(false),
    dienststatus: new FormControl<'JUGEND' | 'AKTIV' | 'RESERVE' | 'ABGEMELDET'>('AKTIV', Validators.required)
  });

  sichtbareSpaltenMitglieder: string[] = ['stbnr', 'vorname', 'nachname', 'dienstgrad', 'dienststatus', 'actions'];

  ngOnInit(): void {
    sessionStorage.setItem("PageNumber", "2");
    sessionStorage.setItem("Page2", "V_M");
    this.breadcrumb = this.globalDataService.ladeBreadcrumb();
    this.formModul.disable();

    this.globalDataService.get(this.modul).subscribe({
      next: (erg: any) => {
        try {
          this.mitglieder = this.globalDataService.arraySortByKey(erg, 'stbnr');
          this.dataSource.data = this.mitglieder;
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (!input.files?.length) {
      return;
    }
    const file = input.files[0];

    Papa.parse<any>(file, {
      header: true,
      skipEmptyLines: true,
      delimiter: ';',
      complete: (results: any) => {
        const parsed: any[] = results.data;

        if (parsed.length > 0) {
          this.previewImport(parsed);
        } else {
          this.globalDataService.erstelleMessage('info', 'Keine CSV-Daten gefunden.');
        }

        input.value = '';
      },
      error: () => this.globalDataService.erstelleMessage('error', 'CSV Parsing Fehler.')
    });
  }

  transformArray<T extends Record<string, any>>(
    inputArray: T[],
    keysToPickAndRename: RenameMap
  ): Record<string, any>[] {
    return inputArray.map(obj => {
      const transformed: Record<string, any> = {};
      for (const [oldKey, newKey] of Object.entries(keysToPickAndRename)) {
        if (oldKey in obj) {
          transformed[newKey] = obj[oldKey];
        }
      }
      return transformed;
    });
  }

  applyFilter(value: string): void {
    this.dataSource.filter = (value || '').trim().toLowerCase();
    this.matPaginator?.firstPage();
  }

  previewImport(entries: any[]): void {
    this.importRows = entries;
    const url = `${this.modul}/import`;
    this.globalDataService.post(url, { mode: 'preview', rows: entries }, false).subscribe({
      next: (erg: any) => {
        this.importChanges = erg?.changes ?? [];
        this.importSummary = erg?.summary ?? null;
        this.globalDataService.erstelleMessage('info', `${this.importChanges.length} Änderungen in der Vorschau gefunden.`);
      },
      error: (error: any) => this.globalDataService.errorAnzeigen(error)
    });
  }

  importBestaetigen(): void {
    if (this.importRows.length === 0) {
      this.globalDataService.erstelleMessage('info', 'Keine Importdaten vorhanden.');
      return;
    }

    const url = `${this.modul}/import`;
    this.globalDataService.post(url, { mode: 'apply', rows: this.importRows }, false).subscribe({
      next: (erg: any) => {
        const summary = erg?.summary ?? { created: 0, updated: 0 };
        this.globalDataService.erstelleMessage('success', `${summary.created} neu, ${summary.updated} aktualisiert.`);
        this.importAbbrechen();

        this.globalDataService.get(this.modul).subscribe({
          next: (list: any) => {
            this.mitglieder = this.globalDataService.arraySortByKey(list, 'stbnr');
            this.dataSource.data = this.mitglieder;
          },
          error: (error: any) => this.globalDataService.errorAnzeigen(error)
        });
      },
      error: (error: any) => this.globalDataService.errorAnzeigen(error)
    });
  }

  importAbbrechen(): void {
    this.importRows = [];
    this.importChanges = [];
    this.importSummary = null;
  }

  validDateDDMMYYYY(): ValidatorFn {
    return (control: AbstractControl) => {
      const v: string = control.value;
      if (!v || !/^([0-3]\d)\.([0-1]\d)\.(\d{4})$/.test(v)) {
        return null;
      }
      const [t, m, j] = v.split('.').map(x => +x);
      const d = new Date(j, m - 1, t);
      return (d.getFullYear() === j && d.getMonth() === m - 1 && d.getDate() === t)
        ? null
        : { dateInvalid: true };
    };
  }

  auswahlBearbeiten(element: any): void {
    if (element.id === 0) {
      return;
    }
    const abfrageUrl = `${this.modul}/${element.id}`;

    this.globalDataService.get(abfrageUrl).subscribe({
      next: (erg: any) => {
        try {
          const details: IMitglied = erg;

          this.formModul.enable();
          this.formModul.setValue({
            id: details.id,
            stbnr: details.stbnr,
            vorname: details.vorname,
            nachname: details.nachname,
            dienstgrad: details.dienstgrad ?? '',
            svnr: details.svnr ?? '',
            geburtsdatum: details.geburtsdatum ?? '',
            hauptberuflich: details.hauptberuflich ?? false,
            dienststatus: details.dienststatus ?? 'AKTIV'
          });
        } catch (e: any) {
          this.globalDataService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  neueDetails(): void {
    this.formModul.enable();
  }

  datenLoeschen(): void {
    const id = this.formModul.controls['id'].value!;
    if (!id) {
      this.globalDataService.erstelleMessage('error', 'Kein Mitglied ausgewählt zum Löschen!');
      return;
    }

    this.globalDataService.delete(this.modul, id).subscribe({
      next: (erg: any) => {
        try {
          this.mitglieder = this.mitglieder.filter(m => m.id !== id);
          this.dataSource.data = this.mitglieder;

          this.formModul.reset({
            id: '',
            stbnr: 0,
            vorname: '',
            nachname: '',
            dienstgrad: '',
            svnr: '',
            geburtsdatum: '',
            hauptberuflich: false,
            dienststatus: 'AKTIV'
          });
          this.formModul.disable();

          this.globalDataService.erstelleMessage('success', 'Mitglied erfolgreich gelöscht!');
        } catch (e: any) {
          this.globalDataService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  abbrechen(): void {
    this.globalDataService.erstelleMessage("info", "Mitglied nicht gespeichert!");
    this.formModul.reset({
      id: '',
      stbnr: 0,
      vorname: '',
      nachname: '',
      dienstgrad: '',
      svnr: '',
      geburtsdatum: '',
      hauptberuflich: false,
      dienststatus: 'AKTIV'
    });
    this.formModul.disable();
  }

  datenSpeichern(): void {
    if (this.formModul.invalid) {
      this.globalDataService.erstelleMessage('error', 'Bitte alle Pflichtfelder korrekt ausfüllen!');
      return;
    }

    const objekt: any = this.formModul.value;
    const idValue = this.formModul.controls['id'].value;

    if (!idValue) {
      this.globalDataService.post(this.modul, objekt, false).subscribe({
        next: (erg: any) => {
          try {
            this.mitglieder.push(erg);
            this.mitglieder = this.globalDataService.arraySortByKey(this.mitglieder, 'stbnr');
            this.dataSource.data = this.mitglieder;

            this.formModul.reset({
              id: '',
              stbnr: 0,
              vorname: '',
              nachname: '',
              dienstgrad: '',
              svnr: '',
              geburtsdatum: '',
              hauptberuflich: false,
              dienststatus: 'AKTIV'
            });
            this.formModul.disable();

            this.globalDataService.erstelleMessage('success', 'Mitglied erfolgreich gespeichert!');
          } catch (e: any) {
            this.globalDataService.erstelleMessage('error', e);
          }
        },
        error: (error: any) => this.globalDataService.errorAnzeigen(error)
      });
    } else {
      this.globalDataService.patch(this.modul, idValue, objekt, false).subscribe({
        next: (erg: any) => {
          try {
            this.mitglieder = this.mitglieder.map(m =>
              m.id === erg.id ? erg : m
            );
            this.dataSource.data = this.mitglieder;

            this.formModul.reset({
              id: '',
              stbnr: 0,
              vorname: '',
              nachname: '',
              dienstgrad: '',
              svnr: '',
              geburtsdatum: '',
              hauptberuflich: false,
              dienststatus: 'AKTIV'
            });
            this.formModul.disable();

            this.globalDataService.erstelleMessage('success', 'Mitglied erfolgreich geändert!');
          } catch (e: any) {
            this.globalDataService.erstelleMessage('error', e);
          }
        },
        error: (error: any) => this.globalDataService.errorAnzeigen(error)
      });
    }
  }
}

